 12	struct throughputlog {
 13	  struct logger common;
 14	  void *database;
 15	  int tick_frame_arg;
 16	  int tick_subframe_arg;
 17	  int data_frame_arg;
 18	  int data_subframe_arg;
 19	  int data_arg;
 20	  int last_tick_frame;
 21	  int last_tick_subframe;
 22	  unsigned long bits[1000];
 23	  unsigned long total;
 24	  int insert_point;
 25	  char *tick_event_name;
 26	  unsigned long tick_handler_id;
 27	  /* tick filter - NULL is no filter set */
 28	  void *tick_filter;
 29	};
