 31	static void _event(void *p, event e)
 32	{
 33	  struct throughputlog *l = p;
 34	  int frame;
 35	  int subframe;
 36	  unsigned long value;
 37	
 38	  if (l->common.filter != NULL && filter_eval(l->common.filter, e) == 0)
 39	    return;
 40	
 41	  frame = e.e[l->data_frame_arg].i;
 42	  subframe = e.e[l->data_subframe_arg].i;
 43	
 44	  if (frame != l->last_tick_frame || subframe != l->last_tick_subframe) {
 45	    printf("WARNING: %s:%d: data comes without previous tick!\n",
 46	           __FILE__, __LINE__);
 47	    return;
 48	  }
 49	
 50	  switch (e.e[l->data_arg].type) {
 51	  case EVENT_INT: value = e.e[l->data_arg].i; break;
 52	  case EVENT_ULONG: value = e.e[l->data_arg].ul; break;
 53	  default: printf("%s:%d: unsupported type\n", __FILE__, __LINE__); abort();
 54	  }
 55	
 56	  l->total += value;
 57	  l->bits[l->insert_point] += value;
 58	}
