 60	static void _tick_event(void *p, event e)
 61	{
 62	  struct throughputlog *l = p;
 63	  int i;
 64	  int frame;
 65	  int subframe;
 66	
 67	  if (l->tick_filter != NULL && filter_eval(l->tick_filter, e) == 0)
 68	    return;
 69	
 70	  frame = e.e[l->tick_frame_arg].i;
 71	  subframe = e.e[l->tick_subframe_arg].i;
 72	
 73	  for (i = 0; i < l->common.vsize; i++)
 74	    l->common.v[i]->append(l->common.v[i], frame, subframe, (double)l->total);
 75	
 76	  l->insert_point = (l->insert_point + 1) % 1000;
 77	  l->total -= l->bits[l->insert_point];
 78	  l->bits[l->insert_point] = 0;
 79	
 80	  l->last_tick_frame = frame;
 81	  l->last_tick_subframe = subframe;
 82	}
