120	  }
121	  if (ret->tick_subframe_arg == -1) {
122	    printf("%s:%d: subframe argument '%s' not found in event '%s'\n",
123	        __FILE__, __LINE__, subframe_varname, event_name);
124	    abort();
125	  }
126	  if (strcmp(f.type[ret->tick_frame_arg], "int") != 0) {
127	    printf("%s:%d: argument '%s' has wrong type (should be 'int')\n",
