132	    printf("%s:%d: argument '%s' has wrong type (should be 'int')\n",
133	        __FILE__, __LINE__, subframe_varname);
134	    abort();
135	  }
136	
137	  /* data event */
138	  event_id = event_id_from_name(database, event_name);
139	
140	  ret->common.handler_id = register_handler_function(h,event_id,_event,ret);
141	
142	  f = get_format(database, event_id);
143	
144	  /* look for frame, subframe and data args */
145	  ret->data_frame_arg = -1;
146	  ret->data_subframe_arg = -1;
147	  ret->data_arg = -1;
148	  for (i = 0; i < f.count; i++) {
149	    if (!strcmp(f.name[i], frame_varname)) ret->data_frame_arg = i;
150	    if (!strcmp(f.name[i], subframe_varname)) ret->data_subframe_arg = i;
151	    if (!strcmp(f.name[i], data_varname)) ret->data_arg = i;
152	  }
153	  if (ret->data_frame_arg == -1) {
154	    printf("%s:%d: frame argument '%s' not found in event '%s'\n",
155	        __FILE__, __LINE__, frame_varname, event_name);
156	    abort();
157	  }
158	  if (ret->data_subframe_arg == -1) {
159	    printf("%s:%d: subframe argument '%s' not found in event '%s'\n",
160	        __FILE__, __LINE__, subframe_varname, event_name);
161	    abort();
162	  }
163	  if (ret->data_arg == -1) {
164	    printf("%s:%d: data argument '%s' not found in event '%s'\n",
165	        __FILE__, __LINE__, data_varname, event_name);
166	    abort();
167	  }
168	  if (strcmp(f.type[ret->data_frame_arg], "int") != 0) {
169	    printf("%s:%d: argument '%s' has wrong type (should be 'int')\n",
170	        __FILE__, __LINE__, frame_varname);
171	    abort();
172	  }
173	  if (strcmp(f.type[ret->data_subframe_arg], "int") != 0) {
174	    printf("%s:%d: argument '%s' has wrong type (should be 'int')\n",
175	        __FILE__, __LINE__, subframe_varname);
176	    abort();
177	  }
178	  if (strcmp(f.type[ret->data_arg], "int") != 0 &&
179	      strcmp(f.type[ret->data_arg], "float") != 0) {
180	    printf("%s:%d: argument '%s' has wrong type"
181	           " (should be 'int' or 'float')\n",
182	        __FILE__, __LINE__, data_varname);
183	    abort();
184	  }
185	
186	  return ret;
187	}
