 28	void reset_ue_ids(void)
 29	{
 30	  int i;
 31	  printf("resetting known UEs\n");
 32	  for (i = 0; i < 65536; i++) ue_id[i] = -1;
 33	  ue_id[65535] = 0;
 34	  ue_id[65534] = 1;     /* HACK: to be removed */
 35	  ue_id[2]     = 2;     /* this supposes RA RNTI = 2, very openair specific */
 36	  next_ue_id = 3;
 37	}
