 39	int ue_id_from_rnti(void *_priv, int rnti)
 40	{
 41	  if (rnti < 0) rnti = 65534; /* HACK, to be removed */
 42	
 43	  if (rnti < 0 || rnti > 65535) { printf("bad rnti %d\n", rnti); exit(1); }
 44	  /* rnti not seen yet? give it a new ue_id */
 45	  if (ue_id[rnti] == -1) {
 46	    ue_id[rnti] = next_ue_id;
 47	    next_ue_id++;
 48	  }
 49	  return ue_id[rnti];
 50	}
