102	void is_on_changed(void *_d)
103	{
104	  enb_data *d = _d;
105	  char t;
106	
107	  if (pthread_mutex_lock(&d->lock)) abort();
108	
109	  if (d->socket == -1) goto no_connection;
110	
111	  t = 1;
112	  if (socket_send(d->socket, &t, 1) == -1 ||
113	      socket_send(d->socket, &d->nevents, sizeof(int)) == -1 ||
114	      socket_send(d->socket, d->is_on, d->nevents * sizeof(int)) == -1)
115	    goto connection_dies;
116	
117	no_connection:
118	  if (pthread_mutex_unlock(&d->lock)) abort();
119	  return;
120	
121	connection_dies:
122	  close(d->socket);
123	  d->socket = -1;
124	  if (pthread_mutex_unlock(&d->lock)) abort();
125	}
