134	static filter *ticktime_filter(void *database, char *event, int i, int ue)
135	{
136	  /* filter is "harq_pid == i && UE_id == 0 && eNB_id == 0" */
137	  /* we get the UE_id from the rnti */
138	  return
139	    filter_and(
140	      filter_eq(filter_evarg(database, event, "harq_pid"), filter_int(i)),
141	      filter_and(
142	        filter_eq(
143	          filter_evfun(database, ue_id_from_rnti, NULL,
144	            filter_evarg(database, event, "rnti")),
145	          filter_int(ue)),
146	        filter_eq(filter_evarg(database, event, "eNB_ID"), filter_int(0))));
147	}
